bool AActor::WasRecentlyRendered(float Tolerance)
{
    static struct UFunction* Func = nullptr;
    if (!Func) Func = ClassPrivate->GetFunction("Actor", "WasRecentlyRendered");
    struct
    {
        float Tolerance;
        bool ReturnValue;
    } Parms{};
    Parms.Tolerance = (float)Tolerance;
    this->ProcessEvent(Func, &Parms);
    return Parms.ReturnValue;
}

